     9→import { OrderDetailStatus, type TransactionType } from '../../services/models';
    10→import { getOrderDetail } from '../../services/services';
    11→import { formatToCurrency } from '../../utils/functions';
    12→import { moment } from '../../services/moment';
    13→import {
    14→  getTransactionGainType,
    15→  getFormattedPointsValue,
    16→  getFormattedHighlightText,
    17→  getFormattedPointsValueForMarketplace,
    18→  getPaymentTypeLabel,
    19→  getMarketplaceTitle,
    20→  getCleanedImageUrl,
    21→} from './utils';
    22→import type { MarketplaceContentData, MarketplaceItemData } from './Models';
    23→import { STATUS_COLORS } from './Models';
    24→import MyOrdersDetailView from './view';
    25→
    26→const MyOrdersDetails = ({ route }: ScreenProps<'MyOrdersDetails'>) => {
    27→  const navigation = useNavigation();
    28→  const hasFocused = useRef(false);
    29→  const modalizeRef = useRef<PropsModalizeRef>(null);
    30→  const modalizeRefInfo = useRef<PropsModalizeRef>(null);
    31→
    32→  const { orderDetail, orderDetailActions } = useRootStore(
    33→    useShallow((state) => ({
    34→      orderDetail: state.orderDetail,
    35→      orderDetailActions: state.orderDetailActions,
    36→    })),
    37→  );
    38→
    39→  const transactionId = route.params?.transactionId;
    40→  const passedType = route.params?.type;
    41→  const passedIcon = route.params?.icon;
    42→  const passedStatus = route.params?.status;
    43→  const passedOrigination = route.params?.origination;
    44→
    45→  useFocusEffect(
    46→    useCallback(() => {
    47→      if (!hasFocused.current) {
    48→        eventScreenViewV3(
    49→          'detalhe_pedido',
    50→          'hub_recompensas_spmais',
    51→          'monetizacao',
    52→          {
    53→            location_1: 'monetizacao',
    54→            location_2: 'hub_recompensas_spmais',
    55→            location_3: 'detalhe_pedido',
    56→          },
    57→        );
    58→        hasFocused.current = true;
    59→      }
    60→
    61→      if (transactionId) {
    62→        orderDetailActions.reset();
    63→        getOrderDetail({ transactionId });
    64→      }
    65→
    66→      return () => {
    67→        hasFocused.current = false;
    68→        orderDetailActions.reset();
    69→      };
    70→    }, [transactionId, orderDetailActions]),
    71→  );
    72→
    73→  const handleGoBack = () => {
    74→    navigation.goBack();
    75→  };
    76→
    77→  const handleOpenReportProblem = () => {
    78→    eventSelectContent({
    79→      content_type: 'cta',
    80→      content_id: 'relatar_problema',
    81→      location_1: 'monetizacao',
    82→      location_2: 'hub_recompensas_spmais',
    83→      location_3: 'detalhe_pedido',
    84→    });
    85→
    86→    eventModalView({
    87→      content_id: 'contato_telefones',
    88→      location_1: 'monetizacao',
    89→      location_2: 'hub_recompensas_spmais',
    90→      location_3: 'detalhe_pedido',
    91→    });
    92→
    93→    modalizeRef.current?.open?.();
    94→  };
    95→
    96→  const handleCloseReportProblem = () => {
    97→    modalizeRef.current?.close?.();
    98→  };
    99→
   100→  const handleOpenInfo = () => {
   101→    modalizeRefInfo.current?.open?.();
   102→  };
   103→
   104→  const handleCloseInfo = () => {
   105→    modalizeRefInfo.current?.close?.();
   106→  };
   107→
   108→  const isLoading = orderDetail.status === OrderDetailStatus.LOADING;
   109→  const hasError = orderDetail.status === OrderDetailStatus.ERROR;
   110→  const { height } = Dimensions.get('window');
   111→
   112→  const handleRetry = () => {
   113→    if (transactionId) {
   114→      getOrderDetail({ transactionId });
   115→    }
   116→  };
   117→
   118→  const transaction = orderDetail.orderDetail;
   119→
   120→  const isValidTransactionType = (type: string | undefined): type is TransactionType => {
   121→    return type === 'CREDIT' || type === 'RESCUE' || type === 'EXPIRED' || type === 'REFUNDED';
   122→  };
   123→
   124→  const enrichedTransaction = useMemo(() => {
   125→    if (!transaction) return undefined;
   126→    return {
   127→      ...transaction,
   128→      type: isValidTransactionType(passedType) ? passedType : transaction.type,
   129→      icon: passedIcon || transaction.icon,
   130→      status: passedStatus || transaction.status,
   131→      details: {
   132→        ...transaction.details,
   133→        provider: passedOrigination || transaction.details?.provider || '',
   134→      },
   135→    };
   136→  }, [
   137→    transaction,
   138→    passedType,
   139→    passedIcon,
   140→    passedStatus,
   141→    passedOrigination,
   142→  ]);
   143→
   144→  const isCashback = passedType === 'RESCUE';
   145→
   146→  const processedData = useMemo(() => {
   147→    if (!enrichedTransaction) {
   148→      return {
   149→        cardTitle: '',
   150→        formattedPointsValue: '',
   151→        highlightText: '',
   152→        formattedCurrencyValue: '',
   153→        marketplaceContent: undefined,
   154→        showOrderNumber: false,
   155→        showStatus: false,
   156→        showValue: false,
   157→      };
   158→    }
   159→
   160→    const gainType = getTransactionGainType(enrichedTransaction);
   161→    const formattedCurrencyValue = formatToCurrency(enrichedTransaction.currencyValue);
   162→    const marketplaceValuePoints = enrichedTransaction?.marketplace?.valuePoints;
   163→    const formattedPointsValue =
   164→      marketplaceValuePoints !== undefined && marketplaceValuePoints !== null
   165→        ? `- ${getFormattedPointsValueForMarketplace(marketplaceValuePoints)}`
   166→        : getFormattedPointsValue(enrichedTransaction.amount, enrichedTransaction.type);
   167→    const marketplaceTitle = getMarketplaceTitle(enrichedTransaction);
   168→    const cardTitle = marketplaceTitle || enrichedTransaction.description || '';
   169→    const highlightText = getFormattedHighlightText(enrichedTransaction.date, gainType, moment);
   170→
   171→    const isMarketplace = !!enrichedTransaction?.marketplace;
   172→    const marketplace = enrichedTransaction?.marketplace;
   173→
   174→    let marketplaceContent: MarketplaceContentData | undefined;
   175→    if (isMarketplace && marketplace) {
   176→      const firstOrder = marketplace.orders?.[0];
