   203→            : undefined,
   204→        valuePoints:
   205→          marketplace.valuePoints !== undefined && marketplace.valuePoints !== null
   206→            ? getFormattedPointsValueForMarketplace(marketplace.valuePoints)
   207→            : undefined,
   208→        vendorName: vendorName || undefined,
   209→        items,
   210→      };
   211→    }
   212→
   213→    return {
   214→      cardTitle,
   215→      formattedPointsValue,
   216→      highlightText,
   217→      formattedCurrencyValue,
   218→      marketplaceContent,
   219→      showOrderNumber: !isMarketplace,
   220→      showStatus: !isMarketplace,
   221→      showValue: !isMarketplace,
   222→    };
   223→  }, [enrichedTransaction]);
   224→
   225→  return (
   226→    <MyOrdersDetailView
   227→      handleGoBack={handleGoBack}
   228→      transaction={enrichedTransaction}
   229→      modalizeRef={modalizeRef}
   230→      modalizeRefInfo={modalizeRefInfo}
   231→      handleOpenReportProblem={handleOpenReportProblem}
   232→      handleCloseReportProblem={handleCloseReportProblem}
   233→      handleOpenInfo={handleOpenInfo}
   234→      handleCloseInfo={handleCloseInfo}
   235→      isLoading={isLoading}
   236→      hasError={hasError}
   237→      handleRetry={handleRetry}
   238→      isCashback={isCashback}
   239→      cardTitle={processedData.cardTitle}
   240→      formattedPointsValue={processedData.formattedPointsValue}
   241→      highlightText={processedData.highlightText}
   242→      formattedCurrencyValue={processedData.formattedCurrencyValue}
   243→      marketplaceContent={processedData.marketplaceContent}
   244→      showOrderNumber={processedData.showOrderNumber}
   245→      showStatus={processedData.showStatus}
   246→      showValue={processedData.showValue}
   247→      height={height}
   248→    />
   249→  );
   250→};
   251→
   252→export default MyOrdersDetails;
